import React from 'react';
import { useState } from 'react';
import './Login.css';

export default function Login() {
 const login = ({handlelogin}) =>{
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
 }

 const submitHandler = (e) => {
    e.preventDefault();
    handleLogin(email, password);
    setEmail('');
    setPassword('');
  };

  return (
    <div className="login-root">

      {/* Left Hero */}
      <div className="login-left">
        <div className="login-left-inner">
          {/* <div className="login-hero-tag">Mobile-first Experience</div> */}
          <h1 className="login-hero-title">Drive Your <span>Freedom</span></h1>
          <p className="login-hero-sub">Rent cars on your terms. Transparent pricing, zero deposit, pickup near you.</p>
          <div className="login-features">
            <div className="lf-item"><span className="lf-icon">₹</span><span>Zero Deposit</span></div>
            <div className="lf-item"><span className="lf-icon">📍</span><span>Nearby Pickup</span></div>
            <div className="lf-item"><span className="lf-icon">⚡</span><span>Instant Booking</span></div>
          </div>
        </div>
      </div>

      {/* Right Form */}
      <div className="login-right">
        <div className="login-card">

          <div className="login-logo">
            <span className="logo-mark">
              <img src="/car.png" alt="logo" className="h-8" />
            </span>
            <span className="logo-text">Goro Cars</span>
          </div>

          {/* Tabs */}
          <div className="login-tabs">
            <button className="tab active">Log In</button>
            <button className="tab ">Sign Up</button>
          </div>

          {/* Form Fields */}
          <div className="login-form">
            <div className="form-group">
              <label>Email / Phone</label>
              <input type="text" placeholder="Enter email or phone" />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input type="password" placeholder="Enter password" />
              <span className="forgot">Forgot Password?</span>
            </div>
            <button className="btn-primary">Log In</button>
            <div className="divider"><span>or</span></div>
            <button className="btn-social">
              <img src="https://www.svgrepo.com/show/475656/google-color.svg" alt="G" width={20} />
              Continue with Google
            </button>
            <button className="btn-social">
              <img src="https://www.svgrepo.com/show/475647/facebook-color.svg" alt="F" width={20} />
              Continue with Facebook
            </button>
          </div>

          {/* <button className="btn-guest">Browse as Guest →</button> */}
        </div>
      </div>

    </div>
  );
}
